declare(strict_types=1);require_once __DIR__.'/_layout.php';require_once dirname(__DIR__,2).'/includes/audit.php';exigirPermiso('academic.evaluations.manage');if(($_SERVER['REQUEST_METHOD']??'')!=='POST'||!validarTokenCsrf((string)($_POST['csrf_token']??''))){http_response_code(400);exit;}$pdo=obtenerConexion();$docenteId=docenteSupervisadoAtenea($pdo);$curso=docenteId($_POST['asignatura_id']??0);exigirCursoDocente($pdo,$docenteId,$curso);$titulo=trim(strip_tags((string)($_POST['titulo']??'')));$descripcion=trim(strip_tags((string)($_POST['descripcion']??'')));$estado=(string)($_POST['estado']??'borrador');$nota=(string)($_POST['nota_maxima']??'');$apertura=trim((string)($_POST['fecha_apertura']??''));$cierre=trim((string)($_POST['fecha_cierre']??''));try{if($titulo===''||mb_strlen($titulo)>190||mb_strlen($descripcion)>5000||!in_array($estado,['borrador','publicada','cerrada','inactiva'],true)||!is_numeric($nota)||(float)$nota<=0||(float)$nota>1000)throw new DomainException('Revisa los datos de la evaluación.');$a=$apertura!==''?DateTimeImmutable::createFromFormat('Y-m-d\TH:i',$apertura):null;$c=$cierre!==''?DateTimeImmutable::createFromFormat('Y-m-d\TH:i',$cierre):null;if(($apertura!==''&&!$a)||($cierre!==''&&!$c)||($a&&$c&&$c<=$a))throw new DomainException('Las fechas no son válidas.');$q=$pdo->prepare('INSERT INTO evaluaciones(asignatura_id,docente_id,titulo,descripcion,fecha_apertura,fecha_cierre,nota_maxima,estado) VALUES(:a,:d,:t,:x,:i,:f,:n,:e)');$q->execute(['a'=>$curso,'d'=>$docenteId,'t'=>$titulo,'x'=>$descripcion?:null,'i'=>$a?$a->format('Y-m-d H:i:s'):null,'f'=>$c?$c->format('Y-m-d H:i:s'):null,'n'=>number_format((float)$nota,2,'.',''),'e'=>$estado]);registrarAuditoria(['actor_user_id'=>$_SESSION['usuario_id'],'event_type'=>'academic.evaluation.created','module'=>'academic','entity_type'=>'evaluation','entity_id'=>$pdo->lastInsertId(),'action'=>'create','result'=>'success','description'=>'Evaluación creada para un curso asignado.'], $pdo);docenteFlash('exito','Evaluación guardada.');}catch(Throwable $e){docenteFlash('error',$e instanceof DomainException?$e->getMessage():'No fue posible guardar la evaluación.');}header('Location:'.docenteUrl('evaluaciones.php',['curso'=>$curso]));
